<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;2. Use load_skill_resource to access reference materials</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
